changeSet.sql:
-- Старшие Арканы (The Fool -> the-fool.webp, Wheel of Fortune -> wheel-of-fortune.webp)
UPDATE public.taro_cards
SET image_key = LOWER(REPLACE(name_en, ' ', '-')) || '.webp'
WHERE arcana = 'MAJOR';

-- Младшие Арканы 1-10 с ведущим нулем (swords-01.webp, swords-10.webp)
UPDATE public.taro_cards
SET image_key = LOWER(suit) || '-' || LPAD(number::text, 2, '0') || '.webp'
WHERE arcana = 'MINOR' AND number BETWEEN 1 AND 10;

-- Придворные карты Младших Арканов (page, knight, queen, king)
UPDATE public.taro_cards SET image_key = LOWER(suit) || '-page.webp' WHERE arcana = 'MINOR' AND number = 11;
UPDATE public.taro_cards SET image_key = LOWER(suit) || '-knight.webp' WHERE arcana = 'MINOR' AND number = 12;
UPDATE public.taro_cards SET image_key = LOWER(suit) || '-queen.webp' WHERE arcana = 'MINOR' AND number = 13;
UPDATE public.taro_cards SET image_key = LOWER(suit) || '-king.webp' WHERE arcana = 'MINOR' AND number = 14;
